// // This module is designed to find the position of the highest set bit in a 4-bit input.
// However, it actually finds the position of the lowest set bit.
module priority_encoder (
    input [3:0] in,
    output reg [1:0] pos
);

    always @(*) begin
        if (in[3])
            pos = 2'b11;
        else if (in[2])
            pos = 2'b10;
        else if (in[1])
            pos = 2'b01;
        else
            pos = 2'b00;
    end

endmodule
